<template>
	<view class="body">
		<view class="navbar">
			<view class="nav-item" v-for="(item, index) in tabList" :key="item.state"
				:class="{ current: tabCurrentIndex === index }" @tap="tabClick(index)">
				{{ item.text }}
			</view>
		</view>
		<swiper :current="tabCurrentIndex" style="height: calc(100% - 80rpx);" duration="300" @change="changeTab">
			<swiper-item class="tab-content" v-for="(tag, key) in tabList" :key="tag.state">
				<scroll-view class="list-scroll-content" scroll-y @scrolltolower="loadData">
					<!-- 空白页 -->
					<u-empty text="没有找到任何商品" mode="list" v-if="tag.loaded === true && tag.goodslist.length === 0">
					</u-empty>
					<!-- 商品列表 -->
					<view class="goods-item" v-for="(goods, key) in tag.goodslist" :key="key">

						<!-- 第一次显示轮播样式 -->
						<view class="" v-if="tag.state == 0 && tag.goodslist.length <= 10 && key <=2">
								<view class="">
									{{tag.goodslist.length}}
								</view>
						</view>
						<view class="" v-else>
{{tag.goodslist.length}}
						</view>

					</view>
					<u-loadmore :status="tag.loadingType" :icon-type="iconType" :load-text="loadText" />
					<view class="edgeInsetBottom"></view>
				</scroll-view>
			</swiper-item>
		</swiper>
	</view>
</template>


<script>
	export default {
		data() {
			return {
				sys: this.$util.sys(),
				tabCurrentIndex: 0,
				tabList: [{
						state: 0,
						text: '销量榜',
						loadingType: 'loadmore',
						current_page: 1,
						goodslist: []
					},
					{
						state: 1,
						text: '特价活动榜',
						loadingType: 'loadmore',
						current_page: 1,
						goodslist: []
					}
				],

				iconType: 'flower',
				loadText: {
					loadmore: '上拉加载更多...',
					loading: '努力加载中',
					nomore: '实在没有了'
				},
				limit: 10,


			}
		},
		onLoad(e) {
			this.tabCurrentIndex = e.index
			this.loadData();
		},
		methods: {
			async loadData(source) {

				let item = this.tabList[this.tabCurrentIndex]
				
				if(!item){
					return ;
				}
				//tab切换只有第一次需要加载数据
				if (source === 'tabChange' && item.loaded === true) {
					return;
				}
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
			
				// let params = {};
				await this.$u.api.billboard({
						index: this.tabCurrentIndex,
						page: item.current_page

					})
					.then(res => {

						if (res.data.length == 0) { //没有更多了
							this.tabList[this.tabCurrentIndex].loadingType = 'nomore';
						} else {
							
							//到底了
							if (res.data.length < this.limit) {
								this.tabList[this.tabCurrentIndex].loadingType = 'nomore';
							} else {
								item.current_page++;

							}
							

							this.tabList[this.tabCurrentIndex].goodslist.concat(res.data);
							
							console.log(this.tabList[this.tabCurrentIndex].goodslist);
						}

						//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页
						this.$set(item, 'loaded', true);

					}).catch(res => {})

				// this.loading = false;


				uni.hideLoading()

			},
			//swiper 切换
			changeTab(e) {
				this.tabCurrentIndex = e.target.current;
				this.loadData('tabChange');
			},
			//顶部tab点击
			tabClick(index) {
				this.tabCurrentIndex = index;
			},


		}

	}
</script>

<style lang="scss" scoped scoped>
	page{
		height: 100%;
	}
	.body{
		height: 100%;
	}
	
	
	.body .navbar{
		display: flex;
		flex-direction: row;
		background-color: red;
		justify-content: space-around;
	}
	
	.body .navbar .nav-item{
		width: calc(100%/2);
		text-align: center;
		padding: 10px;
		font-size: 20px;
		font-weight: 700;
	}
	
	.tab-content{
		
	}

</style>
